 *
 * Returned Value:
 *   Zero on success; a negated errno value on failure.
 *
 ****************************************************************************/

static int lpc17_40_stop(struct watchdog_lowerhalf_s *lower)
{
  /* There is no way to disable WDT once it has been started. */

  return -ENOSYS;
}

